import numpy as np

class Board:
    def __init__(self):
        self.grid = np.array([
            [' ']*8 for _ in range(8)
        ])
        # Initialize pieces on the board
        self.initialize_pieces()

    def initialize_pieces(self):
        # Place red pieces
        for i in [0, 2]:
            for j in range(3):
                self.grid[i][j*2] = 'r'
        # Place white pieces
        for i in [5, 7]:
            for j in range(3):
                self.grid[i][(6-j)*2] = 'w'

    def apply_move(self, move):
        start_x, start_y = move.from_pos
        end_x, end_y = move.to_pos
        captured = move.captured
        if captured:
            self.grid[captured[0]][captured[1]] = ' '
        self.grid[start_x][start_y], self.grid[end_x][end_y] = self.grid[end_x][end_y], self.grid[start_x][start_y]

    def render(self):
        for row in self.grid:
            print(' '.join(row))
